    /// <param name = "_pickingRouteId">Picking route</param>
    public void insertNullData(int _insertNullData, WMSPickingRouteID _pickingRouteId)

    {
 
        for(int i = _insertNullData;i < lineDataFive;i++)

        {

            deliveryNoticePackageReceiptTemp.clear();

            deliveryNoticePackageReceiptTemp.DocumentNumber = _pickingRouteId;//_inventTransferTable.TransferId;

            deliveryNoticePackageReceiptTemp.PrintClassification = deliveryNotice;

            deliveryNoticePackageReceiptTemp.insert();
 
            deliveryNoticePackageReceiptTemp.PrintClassification = packageReceipt;

            deliveryNoticePackageReceiptTemp.insert();

        }

    }

    /// <summary>
    /// Get packing and assorted qty
    /// </summary>
    /// <param name = "_qty">Qty</param>
    /// <param name = "_salesUnit">Sales unit</param>
    /// <param name = "_itemId">Item Id</param>
    /// <param name = "_inventDimId">InventDimid</param>
    /// <param name = "_packingUnit">packing Unit</param>
    /// <returns>packing and assorted qty</returns>
    public container getPackageAssortedQty(Qty _qty, UnitOfMeasureSymbol _salesUnit, ItemId _itemId, InventDimId _inventDimId, UnitOfMeasureSymbol _packingUnit = '')
    {
        real packQty, assortmentQty;

        if(_itemId == nullValueBaseType(Types::String)
            ||_salesUnit == nullValueBaseType(Types::String)
            || _inventDimId == nullValueBaseType(Types::String))
        {
            throw Error(strFmt("@SYS118114", "@KJP:KJP104077"));
        }
        if (EcoResProductUnitConverter::canBeConvertedGivenUnitSymbolsForReleasedProduct(_itemId, _inventDimId,_salesUnit,_packingUnit)
            && _packingUnit != nullValueBaseType(Types::String))
        {
            packQty     = EcoResProductUnitConverter::convertGivenUnitSymbolsForReleasedProduct(_itemId, _inventDimId, _qty,_salesUnit,_packingUnit,NoYes::No,NoYes::No); // Convert Invent to Packing
            packQty     = roundDownDec(packQty,UnitOfMeasure::findBySymbol(_packingUnit).DecimalPrecision);
            assortmentQty = EcoResProductUnitConverter::convertGivenUnitSymbolsForReleasedProduct(_itemId,_inventDimId,packQty,_packingUnit,_salesUnit,NoYes::No,NoYes::Yes); // convert Packing to invent
            assortmentQty = _qty - assortmentQty;
        }
        else
        {
            assortmentQty = _qty;
        }

        return [trunc(packQty), assortmentQty];
    }
